def main():
    k = int(input())
    q = input()
    if k * 26 < len(q):
        print("NO")
        return
    ans = [''] * k
    for i in range(k):
        ans[i] += chr(ord('a') + i)
    for i in range(k):
        if len(ans[i]) < len(q):
            ans[i] += q[len(ans[i])]
    if len(set(ans)) < k:
        print("NO")
        return
    print("YES")
    for i in range(k):
        print(ans[i])


if __name__ == "__main__":
    main()
